    "claudePromptGameVariation": " Lote de preguntas #",
    "claudePromptGameEnd": "\n\nGenera exactamente 5 declaraciones VERDADERAS y 2 declaraciones FALSAS sobre este tema:\n- Las 5 declaraciones verdaderas deben ser factuales, precisas y cubrir diferentes aspectos del tema\n- Las 2 declaraciones falsas deben ser plausibles pero \"alucinaciones\" incorrectas\n- Ajusta la complejidad según el nivel de dificultad\n- Asegúrate de que los hechos sean diversos y cubran diferentes subtemas\n\nHaz que las declaraciones falsas sean creíbles pero claramente incorrectas para un experto. Asegúrate de que todas las declaraciones sean interesantes y educativas. Enfócate en diferentes aspectos o detalles del tema para asegurar variedad.\n\nResponde SOLO con un objeto JSON válido en este formato exacto:\n{\n  \"true_statements\": [\"declaración verdadera 1\", \"declaración verdadera 2\", \"declaración verdadera 3\", \"declaración verdadera 4\", \"declaración verdadera 5\"],\n  \"false_statements\": [\"declaración falsa 1\", \"declaración falsa 2\"],\n  \"explanations\": [\"explicación para declaración falsa 1\", \"explicación para declaración falsa 2\"]\n}\n\nEl array de explicaciones debe contener breves explicaciones de por qué cada declaración falsa correspondiente es incorrecta y cuál es la verdad real.\n\nNo incluyas ningún otro texto. Por favor responde en ",
    "fallbackExplanation": "Esta es una explicación de respaldo con contenido de muestra.",
    "fallbackStatements1": ["Esta es una declaración verdadera de muestra sobre biología", "Esta es otra declaración de muestra", "Esta es una declaración de muestra falsa", "Esta es la declaración de muestra final"],
    "fallbackStatements2": ["Aquí hay una declaración de muestra diferente", "Otro hecho de muestra único", "Esta declaración de muestra es incorrecta", "Una verdad de muestra más"],
    "fallbackStatements3": ["Hecho de muestra número uno", "Hecho de muestra número dos", "Este hecho de muestra es falso", "Hecho de muestra número cuatro"],
    "fallbackTopics": ["Segunda Guerra Mundial", "Sistemas del Cuerpo Humano", "Obras de Shakespeare", "Sistema Solar", "Revolución Americana"]
  }
  /* LOCALE_PLACEHOLDER_END */
};

const appLocale = '{{APP_LOCALE}}';
const browserLocale = navigator.languages?.[0] || navigator.language || 'en-US';
const findMatchingLocale = (locale) => {
  if (TRANSLATIONS[locale]) return locale;
  const lang = locale.split('-')[0];
  const match = Object.keys(TRANSLATIONS).find(key => key.startsWith(lang + '-'));
  return match || 'en-US';
};
const locale = (appLocale !== '{{APP_LOCALE}}') ? findMatchingLocale(appLocale) : findMatchingLocale(browserLocale);
const t = (key) => TRANSLATIONS[locale]?.[key] || TRANSLATIONS['en-US'][key] || key;

const HallucinationGame = () => {
  const [gameState, setGameState] = useState('setup'); // setup, playing, result, complete
  const [topics, setTopics] = useState([]);
  const [selectedTopic, setSelectedTopic] = useState('');
  const [selectedDifficulty, setSelectedDifficulty] = useState('medium');
  const [selectedQuestionCount, setSelectedQuestionCount] = useState(10);
  const [customTopic, setCustomTopic] = useState('');
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [statements, setStatements] = useState([]);
  const [selectedAnswer, setSelectedAnswer] = useState(null);
  const [correctAnswer, setCorrectAnswer] = useState(null);
  const [score, setScore] = useState(0);
  const [streak, setStreak] = useState(0);
  const [totalQuestions, setTotalQuestions] = useState(0);
  const [questionsAnswered, setQuestionsAnswered] = useState(0);
  const [loading, setLoading] = useState(false);
  const [showExplanation, setShowExplanation] = useState(false);
  const [explanation, setExplanation] = useState('');
  const [questionBatchNumber, setQuestionBatchNumber] = useState(1);
  const [usedStatements, setUsedStatements] = useState(new Set());
  const [gameSessionId, setGameSessionId] = useState('');

  const categories = [
    'Science', 'History', 'Geography', 'Sports',
    'Movies', 'Music', 'Literature', 'Art',
    'Technology', 'Food', 'Animals', 'Space'
  ];

  const difficulties = ['easy', 'medium', 'hard'];
  const questionCounts = [5, 10, 15, 20]; // Keep for backward compatibility but slider now handles 1-25

  useEffect(() => {
    generateTopics();
  }, []);

  const generateTopics = async () => {
    setLoading(true);
    try {
      const randomNum = Math.floor(Math.random() * 10000);

      const response = await window.claude.complete(`${t('claudePromptTopics')}${randomNum}${t('claudePromptTopicsEnd')}${locale} language`);

      const topicList = JSON.parse(response);

      // Randomly select 10 topics from the provided list
      const shuffledTopics = [...topicList];
      for (let i = shuffledTopics.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [shuffledTopics[i], shuffledTopics[j]] = [shuffledTopics[j], shuffledTopics[i]];
      }

      setTopics(shuffledTopics.slice(0, 10));
    } catch (error) {
      console.error('Error generating topics:', error);
      setTopics(t('fallbackTopics'));
    }
    setLoading(false);
  };

  const startGame = (topic) => {
    setSelectedTopic(topic);
    setGameState('playing');
    setScore(0);
    setStreak(0);
    setQuestionsAnswered(0);
    setCurrentQuestionIndex(0);
    setTotalQuestions(selectedQuestionCount);
    setQuestionBatchNumber(1);
    setUsedStatements(new Set());
    setGameSessionId(Date.now() + '-' + Math.random().toString(36).substr(2, 9));
    generateQuestion(topic);
  };

  const generateQuestion = async (topic) => {
    setLoading(true);
    setSelectedAnswer(null);
    setShowExplanation(false);

    let attempts = 0;
    const maxAttempts = 3;

    while (attempts < maxAttempts) {
      try {
        // Create highly unique variation using multiple random elements and session tracking
        const timestamp = new Date().getTime();
        const randomSeed = Math.floor(Math.random() * 1000000);
        const questionVariation = Math.floor(Math.random() * 10000);
        const sessionVariation = Math.floor(Math.random() * 10000);
        const aspectSeed = Math.floor(Math.random() * 100);
        const uniqueId = `${gameSessionId}-${questionBatchNumber}-${currentQuestionIndex}-${timestamp}-${randomSeed}-${questionVariation}-${sessionVariation}`;

        // Create a list of used statement keywords to avoid in the prompt
        const usedKeywords = Array.from(usedStatements).join(', ');
        const avoidanceClause = usedStatements.size > 0 ? 
          `\n\nIMPORTANT: Avoid creating statements similar to these already used: ${usedKeywords.substring(0, 500)}. Focus on completely different aspects, facts, and details about ${topic}. Use different subtopics, time periods, or angles.` : 
          '';

        const aspectHints = [
          "Focus on historical events and dates",
          "Emphasize geographical features and locations", 
          "Cover cultural traditions and customs",
          "Discuss economic and political aspects",
          "Highlight scientific and natural phenomena",
          "Explore artistic and literary contributions",
          "Examine demographic and social characteristics",
          "Detail technological and industrial developments",
          "Investigate ecological and environmental factors",
          "Analyze architectural and urban features"
        ];

        const selectedAspect = aspectHints[aspectSeed % aspectHints.length];

        const response = await window.claude.complete(`${t('claudePromptGame')}${topic}${t('claudePromptGameContent')}${selectedDifficulty}${t('claudePromptGameVariation')}${uniqueId}${avoidanceClause}\n\nFocus area for this question: ${selectedAspect}${t('claudePromptGameEnd')}${locale} language`);

        const gameData = JSON.parse(response);

        // Check if any statements are too similar to previously used ones
        const allStatements = [...gameData.true_statements, ...gameData.false_statements];
        const hasRepeats = allStatements.some(statement => {
          const statementWords = statement.toLowerCase().split(' ').filter(word => word.length > 3);
          return Array.from(usedStatements).some(used => {
            const usedWords = used.toLowerCase().split(' ').filter(word => word.length > 3);
            const commonWords = statementWords.filter(word => usedWords.includes(word));
            return commonWords.length >= Math.min(3, statementWords.length * 0.4);
          });
        });

        if (hasRepeats && attempts < maxAttempts - 1) {
          attempts++;
          console.log(`Attempt ${attempts}: Similar statements detected, regenerating...`);
          continue;
        }

        // Randomly select 3 true statements from the 5 provided
        const shuffledTrueStatements = [...gameData.true_statements];
        for (let i = shuffledTrueStatements.length - 1; i > 0; i--) {
          const j = Math.floor(Math.random() * (i + 1));
          [shuffledTrueStatements[i], shuffledTrueStatements[j]] = [shuffledTrueStatements[j], shuffledTrueStatements[i]];
        }
        const selectedTrueStatements = shuffledTrueStatements.slice(0, 3);

        // Randomly select 1 false statement from the 2 provided
        const falseStatementIndex = Math.floor(Math.random() * 2);
        const selectedFalseStatement = gameData.false_statements[falseStatementIndex];
        const selectedExplanation = gameData.explanations[falseStatementIndex];

        // Store all selected statements to avoid future repeats
        [...selectedTrueStatements, selectedFalseStatement].forEach(statement => {
          setUsedStatements(prev => new Set([...prev, statement]));
        });

        // Randomly decide where to place the false statement (0-3)
        const falseIndex = Math.floor(Math.random() * 4);
        const finalStatements = [];

        // Fill the array by placing true statements and false statement
        let trueStatementIndex = 0;
        for (let i = 0; i < 4; i++) {
          if (i === falseIndex) {
            finalStatements[i] = selectedFalseStatement;
          } else {
            finalStatements[i] = selectedTrueStatements[trueStatementIndex];
            trueStatementIndex++;
          }
        }

        setStatements(finalStatements);
        setCorrectAnswer(falseIndex);
        setExplanation(selectedExplanation);
        break;

      } catch (error) {
        console.error('Error generating game:', error);
        if (attempts === maxAttempts - 1) {
          // Enhanced fallback with more variation
          const sampleStatements = [
            t('fallbackStatements1'),
            t('fallbackStatements2'),
            t('fallbackStatements3')
          ];
          const randomSet = sampleStatements[Math.floor(Math.random() * sampleStatements.length)];

          // Add random variation to fallback
          const variation = Math.floor(Math.random() * 4);
          const modifiedStatements = [...randomSet];
          modifiedStatements[variation] = `${modifiedStatements[variation]} (variant ${Math.floor(Math.random() * 1000)})`;

          setStatements(modifiedStatements);
          setCorrectAnswer(2);
          setExplanation(`${t('fallbackExplanation')} (Question ${currentQuestionIndex + 1})`);
        } else {
          attempts++;
        }
      }
    }
    setLoading(false);
  };

  const submitAnswer = async (answerIndex) => {
    setSelectedAnswer(answerIndex);
    setShowExplanation(true);
    setQuestionsAnswered(prev => prev + 1);

    if (answerIndex === correctAnswer) {
      setScore(prev => prev + 1);
      setStreak(prev => prev + 1);
    } else {
      setStreak(0);
    }

    setGameState('result');
  };

  const nextQuestion = () => {
    if (questionsAnswered >= selectedQuestionCount) {
      setGameState('complete');
    } else {
      setCurrentQuestionIndex(prev => prev + 1);
      // Increment batch number every few questions for more variation
      if ((currentQuestionIndex + 1) % 3 === 0) {
        setQuestionBatchNumber(prev => prev + 1);
      }
      setGameState('playing');
      generateQuestion(selectedTopic);
    }
  };

  const backToMenu = () => {
    setGameState('setup');
    setSelectedTopic('');
    setCustomTopic('');
    setCurrentQuestionIndex(0);
    setQuestionsAnswered(0);
    setQuestionBatchNumber(1);
    setUsedStatements(new Set());
    setGameSessionId('');
  };

  const getAccuracy = () => {
    return questionsAnswered > 0 ? Math.round((score / questionsAnswered) * 100) : 0;
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 text-gray-900">
      {/* Custom CSS for slider */}
      <style jsx>{`
        .slider::-webkit-slider-thumb {
          appearance: none;
          height: 24px;
          width: 24px;
          border-radius: 50%;
          background: #374151;
          cursor: pointer;
          box-shadow: 0 4px 8px rgba(0, 0, 0, 0.2);
          transition: all 0.2s ease;
        }

        .slider::-webkit-slider-thumb:hover {
          background: #1f2937;
          transform: scale(1.1);
        }

        .slider::-moz-range-thumb {
          height: 24px;
          width: 24px;
          border-radius: 50%;
          background: #374151;
          cursor: pointer;
          border: none;
          box-shadow: 0 4px 8px rgba(0, 0, 0, 0.2);
        }
      `}</style>
      {/* Animated Background Elements */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/4 left-1/4 w-64 h-64 bg-gray-200/30 rounded-full blur-3xl animate-pulse"></div>
        <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-gray-300/20 rounded-full blur-3xl animate-pulse delay-1000"></div>
        <div className="absolute top-3/4 left-1/2 w-48 h-48 bg-gray-400/20 rounded-full blur-3xl animate-pulse delay-2000"></div>
      </div>

      <div className="relative z-10 container mx-auto px-4 py-8">
        {/* Header */}
        <header className="text-center mb-12">
          <div className="flex items-center justify-center gap-3 mb-4">
            <h1 className="text-5xl font-bold bg-gradient-to-r from-gray-800 to-gray-600 bg-clip-text text-transparent">
              {t('gameTitle')}
            </h1>
          </div>
          <p className="text-xl text-gray-600 max-w-2xl mx-auto">
            {t('gameSubtitle')}
          </p>
        </header>

        {/* Stats Bar - Show during game and after completion */}
        {(questionsAnswered > 0 || gameState === 'complete') && (
          <div className="bg-white/80 backdrop-blur-md rounded-2xl p-6 mb-8 border border-gray-200 shadow-lg">
            <div className="grid grid-cols-4 gap-6 text-center">
              <div className="flex items-center justify-center gap-2">
                <Trophy className="w-6 h-6 text-yellow-600" />
                <div>
                  <div className="text-2xl font-bold text-gray-800">{score}</div>
                  <div className="text-sm text-gray-600">{t('scoreLabel')}</div>
                </div>
              </div>
              <div className="flex items-center justify-center gap-2">
                <Zap className="w-6 h-6 text-orange-600" />
                <div>
                  <div className="text-2xl font-bold text-gray-800">{streak}</div>
                  <div className="text-sm text-gray-600">{t('streakLabel')}</div>
                </div>
              </div>
              <div className="flex items-center justify-center gap-2">
                <Target className="w-6 h-6 text-green-600" />
                <div>
                  <div className="text-2xl font-bold text-gray-800">{getAccuracy()}%</div>
                  <div className="text-sm text-gray-600">{t('accuracyLabel')}</div>
                </div>
              </div>
              <div className="flex items-center justify-center gap-2">
                <Brain className="w-6 h-6 text-gray-700" />
                <div>
                  <div className="text-2xl font-bold text-gray-800">{questionsAnswered}/{selectedQuestionCount}</div>
                  <div className="text-sm text-gray-600">{t('totalLabel')}</div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Game Setup */}
        {gameState === 'setup' && (
          <div className="max-w-6xl mx-auto">
            <div className="bg-white/90 backdrop-blur-md rounded-3xl p-8 border border-gray-200 shadow-xl">
              <h2 className="text-3xl font-bold text-center mb-8 text-gray-800">
                {t('chooseChallenge')}
              </h2>

              {/* Custom Topic Input */}
              <div className="mb-8">
                <label className="block text-lg font-medium mb-3 text-gray-700">{t('enterTopicLabel')}</label>
                <div className="flex gap-3">
                  <input
                    type="text"
                    value={customTopic}
                    onChange={(e) => setCustomTopic(e.target.value)}
                    placeholder={t('topicPlaceholder')}
                    className="flex-1 px-4 py-3 bg-gray-50 border border-gray-300 rounded-xl placeholder-gray-500 text-gray-900 focus:outline-none focus:ring-2 focus:ring-gray-400 focus:border-transparent"
                  />
                  <button
                    onClick={() => startGame(customTopic)}
                    disabled={!customTopic.trim() || loading}
                    className="px-6 py-3 bg-gradient-to-r from-gray-600 to-gray-700 text-white rounded-xl font-medium hover:from-gray-700 hover:to-gray-800 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    {t('playButton')}
                  </button>
                </div>
              </div>

              <div className="text-center mb-6">
                <span className="text-gray-600">{t('orChooseFrom')}</span>
              </div>

              {/* Categories Section */}
              <div className="bg-gray-50 rounded-2xl p-6 mb-8">
                <h3 className="text-xl font-bold mb-4 text-gray-800 flex items-center gap-2">
                  <Brain className="w-6 h-6" />
                  {t('categories')}
                </h3>
                {loading ? (
                  <div className="text-center py-8">
                    <RefreshCw className="w-6 h-6 animate-spin mx-auto mb-2 text-gray-600" />
                    <p className="text-gray-600 text-sm">{t('generatingTopics')}</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-3">
                    {topics.map((topic, index) => (
                      <button
                        key={index}
                        onClick={() => startGame(topic)}
                        className="p-4 text-sm bg-white rounded-xl border border-gray-200 hover:bg-gray-100 transition-all duration-200 hover:scale-105 hover:shadow-md"
                      >
                        {topic}
                      </button>
                    ))}
                  </div>
                )}
                <div className="mt-4 text-center">
                  <button
                    onClick={generateTopics}
                    className="text-gray-600 hover:text-gray-700 transition-colors flex items-center gap-2 mx-auto text-sm"
                  >
                    <RefreshCw className="w-4 h-4" />
                    {t('getDifferentTopics')}
                  </button>
                </div>
              </div>

              {/* Configuration Options */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
                {/* Difficulty Toggle */}
                <div>
                  <h3 className="text-xl font-bold mb-6 text-gray-800 flex items-center gap-2">
                    <Target className="w-6 h-6" />
                    {t('difficulty')}
                  </h3>
                  <div className="bg-gray-100 p-2 rounded-2xl flex">
                    {difficulties.map((difficulty, index) => (
                      <button
                        key={difficulty}
                        onClick={() => setSelectedDifficulty(difficulty)}
                        className={`flex-1 py-3 px-4 rounded-xl font-medium transition-all duration-300 ${
                          selectedDifficulty === difficulty
                            ? 'bg-white text-gray-800 shadow-md transform scale-105'
                            : 'text-gray-600 hover:text-gray-800'
                        }`}
                      >
                        {t(difficulty)}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Question Count Slider */}
                <div>
                  <h3 className="text-xl font-bold mb-6 text-gray-800 flex items-center gap-2">
                    <Sparkles className="w-6 h-6" />
                    {t('numberOfQuestions')}
                  </h3>
                  <div className="space-y-4">
                    <div className="text-center">
                      <span className="text-3xl font-bold text-gray-700">{selectedQuestionCount}</span>
                      <span className="text-lg text-gray-500 ml-2">questions</span>
                    </div>
                    <div className="px-2">
                      <input
                        type="range"
                        min="1"
                        max="25"
                        step="1"
                        value={selectedQuestionCount}
                        onChange={(e) => setSelectedQuestionCount(parseInt(e.target.value))}
                        className="w-full h-3 bg-gray-200 rounded-lg appearance-none cursor-pointer slider"
                        style={{
                          background: `linear-gradient(to right, #6b7280 0%, #6b7280 ${((selectedQuestionCount - 1) / 24) * 100}%, #e5e7eb ${((selectedQuestionCount - 1) / 24) * 100}%, #e5e7eb 100%)`
                        }}
                      />
                      <div className="flex justify-between text-sm text-gray-500 mt-2">
                        <span>1</span>
                        <span>5</span>
                        <span>10</span>
                        <span>15</span>
                        <span>20</span>
                        <span>25</span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Game Play */}
        {gameState === 'playing' && (
          <div className="max-w-4xl mx-auto">
            <div className="bg-white/90 backdrop-blur-md rounded-3xl p-8 border border-gray-200 shadow-xl">
              <div className="text-center mb-8">
                <div className="flex items-center justify-center gap-4 mb-4">
                  <h2 className="text-2xl font-bold text-gray-800">{t('topicPrefix')}{selectedTopic}</h2>
                  <span className="bg-gray-200 text-gray-700 px-3 py-1 rounded-full text-sm font-medium">
                    {currentQuestionIndex + 1}/{selectedQuestionCount}
                  </span>
                </div>
                <p className="text-gray-600 flex items-center justify-center gap-2">
                  <AlertTriangle className="w-5 h-5 text-yellow-600" />
                  {t('findHallucination')}
                </p>
              </div>

              {loading ? (
                <div className="text-center py-12">
                  <RefreshCw className="w-8 h-8 animate-spin mx-auto mb-4 text-gray-600" />
                  <p className="text-gray-600">{t('generatingChallenge')}</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {statements.map((statement, index) => (
                    <button
                      key={index}
                      onClick={() => submitAnswer(index)}
                      className="w-full p-6 bg-gradient-to-r from-gray-50 to-gray-100 rounded-2xl border border-gray-200 hover:from-gray-100 hover:to-gray-150 transition-all duration-300 hover:scale-[1.02] text-left hover:shadow-lg"
                    >
                      <div className="flex items-start gap-4">
                        <div className="w-8 h-8 bg-gray-300 rounded-full flex items-center justify-center font-bold text-gray-700 flex-shrink-0 mt-1">
                          {index + 1}
                        </div>
                        <div className="text-lg leading-relaxed text-gray-800">{statement}</div>
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}

        {/* Result */}
        {gameState === 'result' && (
          <div className="max-w-4xl mx-auto">
            <div className="bg-white/90 backdrop-blur-md rounded-3xl p-8 border border-gray-200 shadow-xl">
              <div className="text-center mb-8">
                {selectedAnswer === correctAnswer ? (
                  <div className="text-green-600">
                    <CheckCircle className="w-16 h-16 mx-auto mb-4" />
                    <h2 className="text-3xl font-bold mb-2">{t('correctTitle')}</h2>
                    <p className="text-xl">{t('correctMessage')}</p>
                  </div>
                ) : (
                  <div className="text-red-600">
                    <XCircle className="w-16 h-16 mx-auto mb-4" />
                    <h2 className="text-3xl font-bold mb-2">{t('incorrectTitle')}</h2>
                    <p className="text-xl">{t('incorrectMessage')}</p>
                  </div>
                )}
              </div>

              <div className="space-y-4 mb-8">
                {statements.map((statement, index) => (
                  <div
                    key={index}
                    className={`p-6 rounded-2xl border-2 ${
                      index === correctAnswer
                        ? 'bg-red-50 border-red-300'
                        : 'bg-green-50 border-green-300'
                    }`}
                  >
                    <div className="flex items-start gap-4">
                      <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold flex-shrink-0 mt-1 ${
                        index === correctAnswer ? 'bg-red-500 text-white' : 'bg-green-500 text-white'
                      }`}>
                        {index === correctAnswer ? '✗' : '✓'}
                      </div>
                      <div>
                        <div className="text-lg leading-relaxed mb-2 text-gray-800">{statement}</div>
                        <div className={`text-sm font-medium ${
                          index === correctAnswer ? 'text-red-600' : 'text-green-600'
                        }`}>
                          {index === correctAnswer ? t('hallucinationLabel') : t('trueLabel')}
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              <div className="bg-blue-50 border border-blue-200 rounded-2xl p-6 mb-8">
                <h3 className="text-xl font-bold mb-3 text-blue-800">{t('explanationTitle')}</h3>
                <p className="text-gray-700 leading-relaxed">{explanation}</p>
              </div>

              <div className="text-center">
                <button
                  onClick={nextQuestion}
                  className="px-8 py-4 bg-gradient-to-r from-gray-600 to-gray-700 text-white rounded-2xl font-bold text-lg hover:from-gray-700 hover:to-gray-800 transition-all hover:scale-105"
                >
                  {questionsAnswered >= selectedQuestionCount ? t('backToMenuButton') : t('nextQuestionButton')}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Game Complete */}
        {gameState === 'complete' && (
          <div className="max-w-4xl mx-auto">
            <div className="bg-white/90 backdrop-blur-md rounded-3xl p-8 border border-gray-200 shadow-xl text-center">
              <Trophy className="w-20 h-20 mx-auto mb-6 text-yellow-500" />
              <h2 className="text-4xl font-bold mb-4 text-gray-800">{t('gameComplete')}</h2>
              <p className="text-xl text-gray-600 mb-8">{t('gameOverMessage')}</p>

              <div className="bg-gray-50 rounded-2xl p-8 mb-8">
                <h3 className="text-2xl font-bold mb-4 text-gray-800">{t('finalScore')}</h3>
                <div className="text-6xl font-bold text-gray-700 mb-4">{score}/{selectedQuestionCount}</div>
                <div className="text-xl text-gray-600">{getAccuracy()}% {t('accuracyLabel')}</div>
              </div>

              <button
                onClick={backToMenu}
                className="px-8 py-4 bg-gradient-to-r from-gray-600 to-gray-700 text-white rounded-2xl font-bold text-lg hover:from-gray-700 hover:to-gray-800 transition-all hover:scale-105"
              >
                {t('backToMenuButton')}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default HallucinationGame;
